from dataclasses import dataclass


@dataclass
class StepGuard:
    max_steps: int
    _step: int = 0

    def tick(self) -> None:
        """Advance the counter at the start of each loop iteration."""
        self._step += 1

    @property
    def step(self) -> int:
        return self._step

    def exhausted(self) -> bool:
        return self._step >= self.max_steps

    def remaining(self) -> int:
        return max(0, self.max_steps - self._step)


# Usage in an agent loop
guard = StepGuard(max_steps=15)

while True:
    guard.tick()
